-- =============================================================================
-- Батч 002: seed значень перечислень. Ідемпотентний (MERGE за ENUM_TYPE+VALUE_KEY).
-- Виконувати з NLS_LANG=.AL32UTF8.
-- =============================================================================
SET DEFINE OFF

-- Enum.RSD_ВерсииСемиКонцепций — Версії семи концепцій (2)
MERGE INTO RSD_ENUMS t USING (SELECT 'RSD_ВерсииСемиКонцепций' enum_type, 'Черновик' value_key, 'Чорновик' name, 10 sort_order FROM dual) s ON (t.ENUM_TYPE=s.enum_type AND t.VALUE_KEY=s.value_key) WHEN MATCHED THEN UPDATE SET t.NAME=s.name, t.SORT_ORDER=s.sort_order WHEN NOT MATCHED THEN INSERT (ENUM_TYPE,VALUE_KEY,NAME,SORT_ORDER) VALUES (s.enum_type,s.value_key,s.name,s.sort_order);
MERGE INTO RSD_ENUMS t USING (SELECT 'RSD_ВерсииСемиКонцепций' enum_type, 'Действует' value_key, 'Діє' name, 20 sort_order FROM dual) s ON (t.ENUM_TYPE=s.enum_type AND t.VALUE_KEY=s.value_key) WHEN MATCHED THEN UPDATE SET t.NAME=s.name, t.SORT_ORDER=s.sort_order WHEN NOT MATCHED THEN INSERT (ENUM_TYPE,VALUE_KEY,NAME,SORT_ORDER) VALUES (s.enum_type,s.value_key,s.name,s.sort_order);

